```csharp
// Break: stopp ved første treff
int[] tall = { 3, 7, 2, 9, 1 };
int mål = 9;

for (int i = 0; i < tall.Length; i++)
{
    if (tall[i] == mål)
    {
        Console.WriteLine($"Funnet på indeks {i}"); // 3
        break; // stopp søket
    }
}

// Continue: hopp over partall
for (int i = 0; i < 6; i++)
{
    if (i % 2 == 0) continue;
    Console.Write(i + " "); // 1 3 5
}
```

